import{_ as e,o as n,c as t,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Tournament Management","description":"","frontmatter":{},"headers":[],"relativePath":"schedule/tournaments.md","filePath":"schedule/tournaments.md"}'),r={name:"schedule/tournaments.md"};function l(i,a,s,m,d,g){return n(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="tournament-management" tabindex="-1">Tournament Management <a class="header-anchor" href="#tournament-management" aria-label="Permalink to &quot;Tournament Management&quot;">​</a></h1><p>Diamond Analytics handles tournament scheduling with support for pool play, bracket games, TBD opponents, and final placement recording.</p><h2 id="adding-a-tournament" tabindex="-1">Adding a Tournament <a class="header-anchor" href="#adding-a-tournament" aria-label="Permalink to &quot;Adding a Tournament&quot;">​</a></h2><ol><li>Navigate to <strong>Schedule</strong></li><li>Tap <strong>+ Tournament</strong></li><li>Enter: <ul><li><strong>Tournament name</strong> — e.g. &quot;Midwest Invitational&quot;</li><li><strong>Location</strong> — city or facility name</li><li><strong>Start date</strong> and <strong>End date</strong></li><li><strong>Format</strong> — Pool Play + Bracket, Round Robin, or Single Elimination</li></ul></li><li>Tap <strong>Save</strong></li></ol><p>The tournament appears as a grouped card on your schedule showing all games within it.</p><h2 id="adding-pool-play-games" tabindex="-1">Adding Pool Play Games <a class="header-anchor" href="#adding-pool-play-games" aria-label="Permalink to &quot;Adding Pool Play Games&quot;">​</a></h2><p>From the tournament detail screen tap <strong>+ Game</strong> to add pool play games. Pool play opponents are usually known in advance — select or add the opponent for each game slot.</p><h2 id="adding-bracket-games" tabindex="-1">Adding Bracket Games <a class="header-anchor" href="#adding-bracket-games" aria-label="Permalink to &quot;Adding Bracket Games&quot;">​</a></h2><p>Bracket games are added the same way. For games where the opponent is not yet known:</p><ol><li>Tap <strong>+ Game</strong></li><li>Select <strong>TBD</strong> as the opponent</li><li>Set the date and approximate time</li><li>Save</li></ol><p>When the bracket is released edit each game to replace TBD with the actual opponent.</p><h2 id="scoring-tournament-games" tabindex="-1">Scoring Tournament Games <a class="header-anchor" href="#scoring-tournament-games" aria-label="Permalink to &quot;Scoring Tournament Games&quot;">​</a></h2><p>Score each tournament game exactly as you would a regular season game. Start a game session, select the tournament game, and score normally. The game links automatically to the tournament.</p><h2 id="recording-tournament-placement" tabindex="-1">Recording Tournament Placement <a class="header-anchor" href="#recording-tournament-placement" aria-label="Permalink to &quot;Recording Tournament Placement&quot;">​</a></h2><p>When the tournament is over:</p><ol><li>Open the tournament detail screen</li><li>Tap <strong>Mark Complete</strong></li><li>Select your final placement: <ul><li>Champion</li><li>Runner-Up</li><li>Semi-Final</li><li>Quarter-Final</li><li>Pool Play Only (did not advance to bracket)</li></ul></li><li>Tap <strong>Save</strong></li></ol><p>Champion and Runner-Up placements display as trophy badges on the tournament card. Both badges appear in your season summary on the dashboard.</p>',17)])])}const p=e(r,[["render",l]]);export{u as __pageData,p as default};
